describe("conversationSnapshots table", () => {
  test("table exists in database with correct columns", () => {
    const columns = rawDb
      .prepare("SELECT name, type, [notnull], dflt_value, pk FROM pragma_table_info('conversation_snapshots')")
      .all() as Array<{ name: string; type: string; notnull: number; dflt_value: string | null; pk: number }>;

    const columnMap = new Map(columns.map((c) => [c.name, c]));

    expect(columnMap.get("id")).toMatchObject({ type: "TEXT", pk: 1 });
    expect(columnMap.get("import_id")).toMatchObject({ type: "TEXT", notnull: 1 });
    expect(columnMap.get("label")).toMatchObject({ type: "TEXT", notnull: 1 });
    expect(columnMap.get("is_active")).toMatchObject({ type: "INTEGER", notnull: 1, dflt_value: "0" });
    expect(columnMap.get("created_at")).toMatchObject({ type: "TEXT", notnull: 1 });
    expect(columnMap.get("updated_at")).toMatchObject({ type: "TEXT", notnull: 1 });
  });

  test("has index on import_id", () => {
    const indexes = rawDb
      .prepare("SELECT name FROM sqlite_master WHERE type = 'index' AND tbl_name = 'conversation_snapshots'")
      .all() as Array<{ name: string }>;

    const indexNames = indexes.map((i) => i.name);
    expect(indexNames).toContain("idx_conversation_snapshots_import_id");
  });

  test("foreign key references imports(id) with CASCADE delete", () => {
    const fks = rawDb
      .prepare("PRAGMA foreign_key_list('conversation_snapshots')")
      .all() as Array<{ table: string; from: string; to: string; on_delete: string }>;

    const importFk = fks.find((fk) => fk.from === "import_id");
    expect(importFk).toBeDefined();
    expect(importFk?.table).toBe("imports");
    expect(importFk?.to).toBe("id");
    expect(importFk?.on_delete).toBe("CASCADE");
  });

  test("Drizzle schema exports conversationSnapshots table", () => {
    expect(conversationSnapshots).toBeDefined();
    // Verify the table name in the Drizzle schema
    expect((conversationSnapshots as any)[Symbol.for("drizzle:Name")]).toBe("conversation_snapshots");
  });

  test("can insert and query a row via raw SQL", () => {
    const now = new Date().toISOString();
    const importId = `_test_cs_${Date.now()}`;
    const snapshotId = `_test_snap_${Date.now()}`;

    // Create a temporary import for FK
    rawDb.prepare("INSERT INTO imports (id, source_url, source_platform, mode, status, current_stage, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?)").run(
      importId, "https://test.com", "test", "full", "completed", "done", now, now,
    );

    try {
      rawDb.prepare("INSERT INTO conversation_snapshots (id, import_id, label, is_active, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?)").run(
        snapshotId, importId, "Test Snapshot", 0, now, now,
      );

      const row = rawDb.prepare("SELECT * FROM conversation_snapshots WHERE id = ?").get(snapshotId) as any;
      expect(row.label).toBe("Test Snapshot");
      expect(row.is_active).toBe(0);
    } finally {
      rawDb.prepare("DELETE FROM imports WHERE id = ?").run(importId);
    }
  });
});

describe("messageEdits table", () => {
  test("table exists in database with correct columns", () => {
    const columns = rawDb
      .prepare("SELECT name, type, [notnull], dflt_value, pk FROM pragma_table_info('message_edits')")
      .all() as Array<{ name: string; type: string; notnull: number; dflt_value: string | null; pk: number }>;

