    expect(snapshotFk?.table).toBe("conversation_snapshots");
    expect(snapshotFk?.on_delete).toBe("CASCADE");
  });

  test("Drizzle schema exports messageEdits table", () => {
    expect(messageEdits).toBeDefined();
    expect((messageEdits as any)[Symbol.for("drizzle:Name")]).toBe("message_edits");
  });

  test("enforces unique constraint on (snapshot_id, message_id)", () => {
    const now = new Date().toISOString();
    const importId = `_test_me_${Date.now()}`;
    const snapshotId = `_test_snap_me_${Date.now()}`;
    const messageId = "msg-1";

    rawDb.prepare("INSERT INTO imports (id, source_url, source_platform, mode, status, current_stage, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?)").run(
      importId, "https://test.com", "test", "full", "completed", "done", now, now,
    );
    rawDb.prepare("INSERT INTO conversation_snapshots (id, import_id, label, is_active, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?)").run(
      snapshotId, importId, "Test", 0, now, now,
    );

    try {
      rawDb.prepare("INSERT INTO message_edits (id, import_id, snapshot_id, message_id, edited_blocks_json, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?)").run(
        `edit-1-${Date.now()}`, importId, snapshotId, messageId, "[]", now, now,
      );

      // Duplicate (snapshot_id, message_id) should fail
      expect(() =>
        rawDb.prepare("INSERT INTO message_edits (id, import_id, snapshot_id, message_id, edited_blocks_json, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?)").run(
          `edit-2-${Date.now()}`, importId, snapshotId, messageId, "[]", now, now,
        ),
      ).toThrow();
    } finally {
      rawDb.prepare("DELETE FROM imports WHERE id = ?").run(importId);
    }
  });
});

