  1→import type { MessageDeletion } from "@chat-exporter/shared";
  2→import { and, eq } from "drizzle-orm";
  3→import { db, withTransaction } from "../db/client.js";
  4→import { imports, messageDeletions } from "../db/schema.js";
  5→
  6→export function listDeletions(importId: string): MessageDeletion[] {
  7→  const rows = db
  8→    .select()
  9→    .from(messageDeletions)
 10→    .where(eq(messageDeletions.importId, importId))
 11→    .all();
 12→
 13→  return rows.map((r) => ({
 14→    id: r.id,
 15→    importId: r.importId,
 16→    messageId: r.messageId,
 17→    reason: r.reason ?? undefined,
 18→    deletedAt: r.deletedAt,
 19→  }));
 20→}
 21→
 22→export function softDeleteMessage(
 23→  importId: string,
 24→  messageId: string,
 25→  reason?: string,
 26→): MessageDeletion {
 27→  const id = crypto.randomUUID();
 28→  const deletedAt = new Date().toISOString();
 29→
 30→  db.insert(messageDeletions)
 31→    .values({ id, importId, messageId, reason: reason ?? null, deletedAt })
 32→    .run();
 33→
 34→  return { id, importId, messageId, reason, deletedAt };
 35→}
 36→
 37→export function softDeleteRound(
 38→  importId: string,
 39→  userMessageId: string,
 40→  reason?: string,
 41→): MessageDeletion[] {
 42→  const row = db
 43→    .select({ conversationJson: imports.conversationJson })
 44→    .from(imports)
 45→    .where(eq(imports.id, importId))
 46→    .get();
 47→
 48→  if (!row?.conversationJson) {
 49→    throw new Error("Import oder Conversation nicht gefunden.");
 50→  }
 51→
 52→  const conversation = JSON.parse(row.conversationJson);
 53→  const messages: Array<{ id: string; role: string }> = conversation.messages;
 54→
 55→  const userIdx = messages.findIndex((m) => m.id === userMessageId);
 56→  if (userIdx === -1) {
 57→    throw new Error("User-Message nicht gefunden.");
 58→  }
 59→
 60→  // Collect user message + all following non-user messages (the "round")
 61→  const roundMessageIds = [userMessageId];
 62→  for (let i = userIdx + 1; i < messages.length; i++) {
 63→    const msg = messages[i];
 64→    if (!msg || msg.role === "user") break;
 65→    roundMessageIds.push(msg.id);
 66→  }
 67→
 68→  return withTransaction(() => {
 69→    const deletions: MessageDeletion[] = [];
 70→    for (const msgId of roundMessageIds) {
 71→      // Skip if already deleted (unique constraint)
 72→      const existing = db
 73→        .select()
 74→        .from(messageDeletions)
 75→        .where(
 76→          and(
 77→            eq(messageDeletions.importId, importId),
 78→            eq(messageDeletions.messageId, msgId),
 79→          ),
 80→        )
 81→        .get();
 82→
 83→      if (!existing) {
 84→        deletions.push(softDeleteMessage(importId, msgId, reason));
 85→      }
 86→    }
 87→    return deletions;
 88→  });
 89→}
 90→
 91→export function restoreMessage(importId: string, messageId: string): boolean {
 92→  const result = db
 93→    .delete(messageDeletions)
 94→    .where(
 95→      and(
 96→        eq(messageDeletions.importId, importId),
 97→        eq(messageDeletions.messageId, messageId),
 98→      ),
 99→    )
100→    .run();
101→
102→  return result.changes > 0;
