import { eq } from "drizzle-orm";
import { afterEach, describe, expect, test } from "vitest";

import { db } from "../db/client.js";
import {
  conversationSnapshots,
  imports,
  messageEdits,
} from "../db/schema.js";
import {
  countEdits,
  deleteAllEditsForSnapshot,
  deleteMessageEdit,
  getMessageEdit,
  listMessageEdits,
  saveMessageEdit,
} from "./edit-repository.js";

// --- Test helpers ---

const createdImportIds: string[] = [];
const createdSnapshotIds: string[] = [];

function insertTestImport(id: string) {
  db.insert(imports)
    .values({
      id,
      sourceUrl: "https://chatgpt.com/share/test",
      sourcePlatform: "chatgpt",
      mode: "archive",
      status: "completed",
      currentStage: "done",
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      warningsJson: "[]",
    })
    .run();
  createdImportIds.push(id);
}

function insertTestSnapshot(id: string, importId: string) {
  db.insert(conversationSnapshots)
    .values({
      id,
      importId,
      label: "Test Snapshot",
      isActive: 1,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    })
    .run();
  createdSnapshotIds.push(id);
}

afterEach(() => {
  // Clean up in correct FK order: edits → snapshots → imports
  for (const sid of createdSnapshotIds) {
    db.delete(messageEdits).where(eq(messageEdits.snapshotId, sid)).run();
    db.delete(conversationSnapshots)
      .where(eq(conversationSnapshots.id, sid))
      .run();
  }
  for (const iid of createdImportIds) {
    db.delete(imports).where(eq(imports.id, iid)).run();
  }
  createdImportIds.length = 0;
  createdSnapshotIds.length = 0;
});

const BLOCKS_JSON = JSON.stringify([
  { type: "paragraph", content: "Edited content" },
]);

const BLOCKS_JSON_V2 = JSON.stringify([
  { type: "paragraph", content: "Updated content" },
]);

describe("saveMessageEdit", () => {
  test("saves a new edit and returns the record", () => {
    insertTestImport("edit-imp-1");
    insertTestSnapshot("edit-snap-1", "edit-imp-1");

    const result = saveMessageEdit(
      "edit-imp-1",
      "edit-snap-1",
      "msg-1",
      BLOCKS_JSON,
    );

    expect(result).toMatchObject({
      importId: "edit-imp-1",
      snapshotId: "edit-snap-1",
      messageId: "msg-1",
      editedBlocksJson: BLOCKS_JSON,
    });
    expect(result.id).toBeTruthy();
    expect(result.createdAt).toBeTruthy();
    expect(result.updatedAt).toBeTruthy();
    expect(result.annotation).toBeNull();
  });

  test("saves edit with annotation", () => {
    insertTestImport("edit-imp-2");
    insertTestSnapshot("edit-snap-2", "edit-imp-2");

    const result = saveMessageEdit(
      "edit-imp-2",
      "edit-snap-2",
      "msg-1",
      BLOCKS_JSON,
      "Fixed typo",
    );

    expect(result.annotation).toBe("Fixed typo");
  });

  test("upserts when same snapshotId+messageId already exists", () => {
    insertTestImport("edit-imp-3");
    insertTestSnapshot("edit-snap-3", "edit-imp-3");

    const first = saveMessageEdit(
      "edit-imp-3",
      "edit-snap-3",
      "msg-1",
      BLOCKS_JSON,
      "First version",
    );
    const second = saveMessageEdit(
      "edit-imp-3",
      "edit-snap-3",
      "msg-1",
      BLOCKS_JSON_V2,
      "Second version",
    );

    // Should have replaced, not duplicated
    const all = listMessageEdits("edit-snap-3");
    expect(all).toHaveLength(1);
    expect(all[0].editedBlocksJson).toBe(BLOCKS_JSON_V2);
    expect(all[0].annotation).toBe("Second version");
    // ID may change on upsert (INSERT OR REPLACE), that's fine
    expect(second.editedBlocksJson).toBe(BLOCKS_JSON_V2);
  });
});

describe("getMessageEdit", () => {
  test("returns the edit for existing snapshotId+messageId", () => {
    insertTestImport("edit-imp-4");
    insertTestSnapshot("edit-snap-4", "edit-imp-4");
    saveMessageEdit("edit-imp-4", "edit-snap-4", "msg-1", BLOCKS_JSON);

    const result = getMessageEdit("edit-snap-4", "msg-1");

    expect(result).toBeDefined();
    expect(result!.messageId).toBe("msg-1");
    expect(result!.editedBlocksJson).toBe(BLOCKS_JSON);
  });

  test("returns undefined for non-existent edit", () => {
    const result = getMessageEdit("nonexistent", "msg-1");

    expect(result).toBeUndefined();
  });
});

describe("listMessageEdits", () => {
  test("returns all edits for a snapshot", () => {
    insertTestImport("edit-imp-5");
    insertTestSnapshot("edit-snap-5", "edit-imp-5");
    saveMessageEdit("edit-imp-5", "edit-snap-5", "msg-1", BLOCKS_JSON);
    saveMessageEdit("edit-imp-5", "edit-snap-5", "msg-2", BLOCKS_JSON_V2);

    const result = listMessageEdits("edit-snap-5");

    expect(result).toHaveLength(2);
    const messageIds = result.map((r) => r.messageId).sort();
    expect(messageIds).toEqual(["msg-1", "msg-2"]);
  });

  test("returns empty array for snapshot with no edits", () => {
    const result = listMessageEdits("nonexistent-snap");

    expect(result).toEqual([]);
  });
});

describe("deleteMessageEdit", () => {
  test("deletes existing edit and returns true", () => {
    insertTestImport("edit-imp-6");
    insertTestSnapshot("edit-snap-6", "edit-imp-6");
    saveMessageEdit("edit-imp-6", "edit-snap-6", "msg-1", BLOCKS_JSON);

    const deleted = deleteMessageEdit("edit-snap-6", "msg-1");

    expect(deleted).toBe(true);
    expect(getMessageEdit("edit-snap-6", "msg-1")).toBeUndefined();
  });

  test("returns false for non-existent edit", () => {
    const deleted = deleteMessageEdit("nonexistent", "msg-1");

    expect(deleted).toBe(false);
  });
});

describe("deleteAllEditsForSnapshot", () => {
  test("deletes all edits and returns count", () => {
    insertTestImport("edit-imp-7");
    insertTestSnapshot("edit-snap-7", "edit-imp-7");
    saveMessageEdit("edit-imp-7", "edit-snap-7", "msg-1", BLOCKS_JSON);
    saveMessageEdit("edit-imp-7", "edit-snap-7", "msg-2", BLOCKS_JSON);
    saveMessageEdit("edit-imp-7", "edit-snap-7", "msg-3", BLOCKS_JSON);

    const count = deleteAllEditsForSnapshot("edit-snap-7");

    expect(count).toBe(3);
    expect(listMessageEdits("edit-snap-7")).toEqual([]);
  });

  test("returns 0 for snapshot with no edits", () => {
    const count = deleteAllEditsForSnapshot("nonexistent-snap");

    expect(count).toBe(0);
  });
});

describe("countEdits", () => {
  test("returns correct count of edits", () => {
    insertTestImport("edit-imp-8");
    insertTestSnapshot("edit-snap-8", "edit-imp-8");
    saveMessageEdit("edit-imp-8", "edit-snap-8", "msg-1", BLOCKS_JSON);
    saveMessageEdit("edit-imp-8", "edit-snap-8", "msg-2", BLOCKS_JSON);

    const result = countEdits("edit-snap-8");

    expect(result).toBe(2);
  });

  test("returns 0 for snapshot with no edits", () => {
    const result = countEdits("nonexistent-snap");

    expect(result).toBe(0);
  });
});

import type { ConversationSnapshot } from "@chat-exporter/shared";
import type { ImportJob } from "@chat-exporter/shared";
import { afterEach, describe, expect, test } from "vitest";

import { deleteImport, insertImport } from "./import-repository.js";
import {
  activateSnapshot,
  createSnapshot,
  deactivateAllSnapshots,
  deleteSnapshot,
  getActiveSnapshot,
  listSnapshots,
  renameSnapshot,
} from "./snapshot-repository.js";

function createTestImportJob(overrides?: Partial<ImportJob>): ImportJob {
  return {
    id: crypto.randomUUID(),
    sourceUrl: "https://chatgpt.com/share/snapshot-test",
    sourcePlatform: "chatgpt",
    mode: "archive",
    status: "completed",
    currentStage: "done",
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    warnings: [],
    ...overrides,
  };
}

const createdImportIds: string[] = [];

function trackImport(job: ImportJob) {
  insertImport(job);
  createdImportIds.push(job.id);
}

afterEach(() => {
  for (const id of createdImportIds) {
    deleteImport(id);
  }
  createdImportIds.length = 0;
});

describe("createSnapshot", () => {
  test("creates snapshot with correct fields and isActive as false", () => {
    const job = createTestImportJob();
    trackImport(job);

    const snapshot = createSnapshot(job.id, "My Snapshot");

    expect(snapshot.id).toBeDefined();
    expect(snapshot.importId).toBe(job.id);
    expect(snapshot.label).toBe("My Snapshot");
    expect(snapshot.isActive).toBe(false);
    expect(snapshot.createdAt).toBeDefined();
    expect(snapshot.updatedAt).toBeDefined();
  });

  test("returns isActive as boolean, not integer", () => {
    const job = createTestImportJob();
    trackImport(job);

    const snapshot = createSnapshot(job.id, "Boolean Check");

    expect(typeof snapshot.isActive).toBe("boolean");
    expect(snapshot.isActive).toBe(false);
  });
});

describe("listSnapshots", () => {
  test("returns empty array when no snapshots exist", () => {
    const job = createTestImportJob();
    trackImport(job);

    const result = listSnapshots(job.id);

    expect(result).toEqual([]);
  });

  test("returns all snapshots for import ordered by createdAt", () => {
    const job = createTestImportJob();
    trackImport(job);

    const first = createSnapshot(job.id, "First");
    const second = createSnapshot(job.id, "Second");

    const result = listSnapshots(job.id);

    expect(result).toHaveLength(2);
    expect(result[0].id).toBe(first.id);
    expect(result[1].id).toBe(second.id);
  });

  test("does not return snapshots from other imports", () => {
    const job1 = createTestImportJob();
    const job2 = createTestImportJob();
    trackImport(job1);
    trackImport(job2);

    createSnapshot(job1.id, "Job1 Snapshot");
    createSnapshot(job2.id, "Job2 Snapshot");

    const result = listSnapshots(job1.id);

    expect(result).toHaveLength(1);
    expect(result[0].label).toBe("Job1 Snapshot");
  });

  test("returns isActive as boolean in list results", () => {
    const job = createTestImportJob();
    trackImport(job);

    createSnapshot(job.id, "Check Type");

    const result = listSnapshots(job.id);

    expect(typeof result[0].isActive).toBe("boolean");
  });
});

describe("getActiveSnapshot", () => {
  test("returns null when no snapshot is active", () => {
    const job = createTestImportJob();
    trackImport(job);

    createSnapshot(job.id, "Inactive");

    const result = getActiveSnapshot(job.id);

    expect(result).toBeNull();
  });

  test("returns the active snapshot after activation", () => {
    const job = createTestImportJob();
    trackImport(job);

    const snapshot = createSnapshot(job.id, "To Activate");
    activateSnapshot(snapshot.id);

    const result = getActiveSnapshot(job.id);

    expect(result).not.toBeNull();
    expect(result!.id).toBe(snapshot.id);
    expect(result!.isActive).toBe(true);
  });
});

describe("activateSnapshot", () => {
  test("activates the specified snapshot", () => {
    const job = createTestImportJob();
    trackImport(job);

    const snapshot = createSnapshot(job.id, "Activate Me");

    const result = activateSnapshot(snapshot.id);

    expect(result.isActive).toBe(true);
    expect(result.id).toBe(snapshot.id);
  });

  test("deactivates all other snapshots of the same import", () => {
    const job = createTestImportJob();
    trackImport(job);

    const first = createSnapshot(job.id, "First");
    const second = createSnapshot(job.id, "Second");

    activateSnapshot(first.id);
    activateSnapshot(second.id);

    const all = listSnapshots(job.id);
    const firstAfter = all.find((s) => s.id === first.id)!;
    const secondAfter = all.find((s) => s.id === second.id)!;

    expect(firstAfter.isActive).toBe(false);
    expect(secondAfter.isActive).toBe(true);
  });

  test("does not affect snapshots from other imports", () => {
    const job1 = createTestImportJob();
    const job2 = createTestImportJob();
    trackImport(job1);
    trackImport(job2);

    const snap1 = createSnapshot(job1.id, "Job1");
    const snap2 = createSnapshot(job2.id, "Job2");
    activateSnapshot(snap2.id);

    activateSnapshot(snap1.id);

    const job2Snap = listSnapshots(job2.id).find((s) => s.id === snap2.id)!;
    expect(job2Snap.isActive).toBe(true);
  });
});

describe("deactivateAllSnapshots", () => {
  test("sets all snapshots of import to inactive", () => {
    const job = createTestImportJob();
    trackImport(job);

    const snap = createSnapshot(job.id, "Active One");
    activateSnapshot(snap.id);

    deactivateAllSnapshots(job.id);

    const all = listSnapshots(job.id);
    for (const s of all) {
      expect(s.isActive).toBe(false);
    }
  });

  test("does not affect snapshots from other imports", () => {
    const job1 = createTestImportJob();
    const job2 = createTestImportJob();
    trackImport(job1);
    trackImport(job2);

